import React, { Component } from 'react';
import { AppBar, Toolbar, Typography, CssBaseline, Container, Box, Grid, Paper, Avatar, IconButton, Chip, Divider } from '@mui/material';
import { createTheme, ThemeProvider, styled } from '@mui/material/styles';
import { Brightness4, Brightness7 } from '@mui/icons-material';

const themeLight = createTheme({
    palette: {
        mode: 'light',
        primary: { main: '#1976d2' },
        background: { default: '#f4f4f4', paper: '#ffffff' }
    }
});

const themeDark = createTheme({
    palette: {
        mode: 'dark',
        primary: { main: '#bb86fc' },
        background: { default: '#121212', paper: '#1e1e1e' }
    }
});

const ProfileAvatar = styled(Avatar)(({ theme }) => ({
    width: 100,
    height: 100,
    marginBottom: theme.spacing(2)
}));

class Dashboard extends Component {
    state = {
        isNightMode: false
    };

    toggleTheme = () => {
        this.setState(prevState => ({ isNightMode: !prevState.isNightMode }));
    };

    handleChipClick = (label) => {
        alert(`Clicked on ${label}`);
    };

    render() {
        const { isNightMode } = this.state;
        const theme = isNightMode ? themeDark : themeLight;

        return (
            <ThemeProvider theme={theme}>
                <CssBaseline />
                <AppBar position="absolute" sx={{ bgcolor: theme.palette.primary.main }}>
                    <Toolbar>
                        <Typography variant="h6" sx={{ flexGrow: 1 }}>
                            Portfolio Dashboard
                        </Typography>
                        <IconButton color="inherit" onClick={this.toggleTheme}>
                            {isNightMode ? <Brightness7 /> : <Brightness4 />}
                        </IconButton>
                    </Toolbar>
                </AppBar>
                <Container sx={{ marginTop: 10 }}>
                    <Paper elevation={3} sx={{ padding: 3, textAlign: 'center' }}>
                        <ProfileAvatar src="/profile.jpg" alt="Profile Picture" />
                        <Typography variant="h5">John Doe</Typography>
                        <Typography variant="body1" color="textSecondary">
                            Full Stack Developer
                        </Typography>
                        <Divider sx={{ marginY: 2 }} />
                        <Grid container spacing={2} justifyContent="center">
                            {['React', 'Node.js', 'MongoDB', 'GraphQL', 'TypeScript'].map(skill => (
                                <Grid item key={skill}>
                                    <Chip label={skill} onClick={() => this.handleChipClick(skill)} />
                                </Grid>
                            ))}
                        </Grid>
                    </Paper>
                </Container>
            </ThemeProvider>
        );
    }
}

export default Dashboard;
